// scripts/verify-dependencies.js
// Pre-build verification script to detect dependency confusion attacks

const fs = require('fs');
const path = require('path');

const PRIVATE_SCOPE = '@company';
const PRIVATE_REGISTRY = 'https://npm.company.com';
const PUBLIC_REGISTRY = 'https://registry.npmjs.org';

function verifyDependencies() {
  const packageJsonPath = path.resolve(__dirname, '..', 'package.json');
  const packageLockPath = path.resolve(__dirname, '..', 'package-lock.json');
  const npmrcPath = path.resolve(__dirname, '..', '.npmrc');

  // 1. Verify .npmrc exists and has scoped registry
  if (!fs.existsSync(npmrcPath)) {
    console.error('ERROR: .npmrc file is missing. Scoped registry configuration is required.');
    process.exit(1);
  }

  const npmrcContent = fs.readFileSync(npmrcPath, 'utf-8');

  const scopedRegistryPattern = new RegExp(
    `${PRIVATE_SCOPE.replace('/', '\\/')}:registry=\\s*${PRIVATE_REGISTRY.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}`
  );

  if (!scopedRegistryPattern.test(npmrcContent)) {
    console.error(
      `ERROR: .npmrc must configure ${PRIVATE_SCOPE} scope to use private registry ${PRIVATE_REGISTRY}`
    );
    console.error('This is required to prevent dependency confusion attacks.');
    process.exit(1);
  }

  console.log('✓ .npmrc has correct scoped registry configuration');

  // 2. Verify package.json
  const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, 'utf-8'));

  if (!packageJson.private) {
    console.error('ERROR: package.json must have "private": true for internal applications.');
    process.exit(1);
  }

  console.log('✓ package.json is marked as private');

  // 3. Collect all dependencies
  const allDeps = {
    ...packageJson.dependencies,
    ...packageJson.devDependencies,
    ...packageJson.optionalDependencies,
  };

  const privateDeps = [];
  const publicDeps = [];
  const suspiciousDeps = [];

  for (const [name, version] of Object.entries(allDeps)) {
    if (name.startsWith(`${PRIVATE_SCOPE}/`)) {
      privateDeps.push({ name, version });

      // Verify private deps don't use URL/git references to public sources
      if (
        version.startsWith('http://') ||
        version.startsWith('git://') ||
        version.startsWith('github:')
      ) {
        suspiciousDeps.push({
          name,
          version,
          reason: 'Private scoped package uses external URL reference',
        });
      }
    } else {
      publicDeps.push({ name, version });
    }
  }

  if (suspiciousDeps.length > 0) {
    console.error('\nERROR: Suspicious dependency references detected:');
    suspiciousDeps.forEach((dep) => {
      console.error(`  - ${dep.name}@${dep.version}: ${dep.reason}`);
    });
    process.exit(1);
  }

  console.log(`✓ ${privateDeps.length} private scoped packages verified`);
  console.log(`✓ ${publicDeps.length} public packages found`);

  // 4. Verify lockfile integrity if it exists
  if (fs.existsSync(packageLockPath)) {
    const packageLock = JSON.parse(fs.readFileSync(packageLockPath, 'utf-8'));
    const packages = packageLock.packages || {};
    let lockfileIssues = [];

    for (const [pkgPath, pkgInfo] of Object.entries(packages)) {
      if (!pkgPath) continue; // Skip root entry

      const pkgName = pkgPath.replace(/^node_modules\//, '');

      // Check that @company packages in lockfile resolve to private registry
      if (pkgName.startsWith(`${PRIVATE_SCOPE}/`)) {
        if (pkgInfo.resolved && !pkgInfo.resolved.startsWith(PRIVATE_REGISTRY)) {
          lockfileIssues.push({
            name: pkgName,
            resolved: pkgInfo.resolved,
            expected: PRIVATE_REGISTRY,
          });
        }
      }

      // Check that non-scoped packages don't resolve to private registry
      // (this would indicate a misconfiguration)
      if (
        !pkgName.startsWith('@') &&
        pkgInfo.resolved &&
        pkgInfo.resolved.startsWith(PRIVATE_REGISTRY)
      ) {
        lockfileIssues.push({
          name: pkgName,
          resolved: pkgInfo.resolved,
          reason: 'Non-scoped package resolving from private registry',
        });
      }
    }

    if (lockfileIssues.length > 0) {
      console.error('\nERROR: Lockfile integrity issues detected:');
      lockfileIssues.forEach((issue) => {
        if (issue.expected) {
          console.error(
            `  - ${issue.name}: resolves to ${issue.resolved}, expected ${issue.expected}`
          );
        } else {
          console.error(`  - ${issue.name}: ${issue.reason} (${issue.resolved})`);
        }
      });
      process.exit(1);
    }

    console.log('✓ Lockfile registry references verified');
  } else {
    console.warn('⚠ No package-lock.json found. Run npm install to generate one.');
  }

  // 5. Check for typosquatting on common internal package names
  const knownInternalPackages = ['auth', 'logger', 'api-client'];
  const potentialTyposquats = [];

  for (const [name] of Object.entries(allDeps)) {
    if (!name.startsWith('@')) {
      for (const internalName of knownInternalPackages) {
        if (name === internalName || name === `company-${internalName}`) {
          potentialTyposquats.push({
            name,
            suggestion: `${PRIVATE_SCOPE}/${internalName}`,
          });
        }
      }
    }
  }

  if (potentialTyposquats.length > 0) {
    console.error('\nWARNING: Potential typosquatting/confusion detected:');
    potentialTyposquats.forEach((dep) => {
      console.error(`  - "${dep.name}" looks like it should be "${dep.suggestion}"`);
    });
    process.exit(1);
  }

  console.log('✓ No typosquatting patterns detected');
  console.log('\n✅ All dependency confusion checks passed.\n');
}

verifyDependencies();